import{_ as a,o as n,c as s,ag as t}from"./chunks/framework.DFlFRONG.js";const u=JSON.parse('{"title":"TeamOne Proxy Server","titleTemplate":"TeamOne Proxy Server","description":"","frontmatter":{"title":"TeamOne Proxy Server","titleTemplate":"TeamOne Proxy Server"},"headers":[],"relativePath":"proxy.md","filePath":"proxy.md"}'),o={name:"proxy.md"};function r(i,e,l,p,c,d){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="teamone-proxy-server" tabindex="-1">TeamOne Proxy Server <a class="header-anchor" href="#teamone-proxy-server" aria-label="Permalink to &quot;TeamOne Proxy Server&quot;">​</a></h1><p>The TeamOne Proxy Server is a customer-managed component that allows the TeamOne Google Sheets add-on to securely connect to customer IBM Planning Analytics / TM1 environments.</p><p>It is commonly used when IBM Planning Analytics / TM1 is not directly accessible from the user’s browser, when the customer wants to control all traffic between Google Sheets and IBM Planning Analytics through their own network, or when TeamOne needs to support SSO login from Google Sheets.</p><p>The TeamOne Proxy Server does <strong>not</strong> replace IBM Planning Analytics security. Users are still authenticated and authorized according to the customer’s IBM Planning Analytics / TM1 configuration.</p><p>Detailed installation and configuration instructions are provided separately as part of the TeamOne Welcome Kit.</p><p>If you have questions about the recommended architecture for your environment, please contact us at <a href="mailto:teamone@succeedium.com" target="_blank" rel="noreferrer">teamone@succeedium.com</a>.</p><h2 id="high-level-request-flow" tabindex="-1">High-level request flow <a class="header-anchor" href="#high-level-request-flow" aria-label="Permalink to &quot;High-level request flow&quot;">​</a></h2><p>At a high level, TeamOne uses the following request flow:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Sheets / TeamOne Add-on</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>TeamOne Proxy Server</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>IBM Planning Analytics / TM1 REST API</span></span></code></pre></div><p>The TeamOne Proxy Server forwards requests only to approved IBM Planning Analytics / TM1 hosts, based on the customer’s configuration and network rules.</p><h2 id="deployment-locations" tabindex="-1">Deployment locations <a class="header-anchor" href="#deployment-locations" aria-label="Permalink to &quot;Deployment locations&quot;">​</a></h2><p>The TeamOne Proxy Server can be deployed in a customer-managed cloud environment or on-premises.</p><h3 id="customer-cloud-deployment" tabindex="-1">Customer cloud deployment <a class="header-anchor" href="#customer-cloud-deployment" aria-label="Permalink to &quot;Customer cloud deployment&quot;">​</a></h3><p>Most TeamOne Proxy Server deployments are installed on customer-managed cloud infrastructure, such as:</p><ul><li>AWS EC2</li><li>Azure VM</li><li>GCP VM</li><li>other customer-managed cloud infrastructure</li></ul><h3 id="on-premises-deployment" tabindex="-1">On-premises deployment <a class="header-anchor" href="#on-premises-deployment" aria-label="Permalink to &quot;On-premises deployment&quot;">​</a></h3><p>The TeamOne Proxy Server can also be installed on a customer-managed Linux server or virtual machine inside the corporate network.</p><p>In both cloud and on-premises deployments, two network requirements must be satisfied:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User browser / Google Sheets → TeamOne Proxy Server</span></span>
<span class="line"><span>TeamOne Proxy Server → IBM Planning Analytics / TM1</span></span></code></pre></div><p>The user’s browser must be able to reach the TeamOne Proxy Server endpoint, and the TeamOne Proxy Server must be able to reach the approved IBM Planning Analytics / TM1 hosts and ports.</p><h2 id="public-address-space-requirement" tabindex="-1">Public address-space requirement <a class="header-anchor" href="#public-address-space-requirement" aria-label="Permalink to &quot;Public address-space requirement&quot;">​</a></h2><p>Modern browser security controls, including Chrome Local Network Access, may require the TeamOne Proxy Server endpoint to be reachable using a public address-space IP.</p><p>This does <strong>not</strong> mean the TeamOne Proxy Server must be open to the entire internet.</p><p>A public address-space IP can still be protected using standard network controls, such as:</p><ul><li>corporate VPN</li><li>Zscaler or another secure access gateway</li><li>firewall rules</li><li>AWS Security Groups</li><li>load balancer policies</li><li>approved corporate source IP ranges</li></ul><p>The key requirement is that the TeamOne Proxy Server endpoint must resolve to an IP address that the browser treats as public address space. This may be a public cloud IP address, such as an AWS Elastic IP, or another public address-space IP approved by the customer’s network team.</p><p>Carrier-Grade NAT (CGNAT) and private/internal IP ranges are not sufficient for this browser requirement.</p><p>More details about this requirement are available <a href="https://docs.google.com/document/d/1YntAQ6UyRVnZbSjMp51vRg4CwIGq7Xt2IS-1us0zeUk" target="_blank" rel="noreferrer">here</a>.</p><h2 id="tls-ssl-deployment-options" tabindex="-1">TLS / SSL deployment options <a class="header-anchor" href="#tls-ssl-deployment-options" aria-label="Permalink to &quot;TLS / SSL deployment options&quot;">​</a></h2><p>The TeamOne Proxy Server supports two common SSL certificate deployment models. The right option depends on the customer’s network design and certificate management standards.</p><h3 id="option-1-—-ssl-certificate-managed-on-the-teamone-proxy-server" tabindex="-1">Option 1 — SSL certificate managed on the TeamOne Proxy Server <a class="header-anchor" href="#option-1-—-ssl-certificate-managed-on-the-teamone-proxy-server" aria-label="Permalink to &quot;Option 1 — SSL certificate managed on the TeamOne Proxy Server&quot;">​</a></h3><p>In this option, the TeamOne Proxy Server handles HTTPS directly.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser / Google Sheets</span></span>
<span class="line"><span>        ↓ HTTPS</span></span>
<span class="line"><span>TeamOne Proxy Server</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>IBM Planning Analytics / TM1</span></span></code></pre></div><p>Use this option when:</p><ul><li>a standalone cloud or on-premises server is used</li><li>there is no load balancer handling SSL</li></ul><p>In this model, the customer installs and renews the SSL certificate files on the TeamOne Proxy Server.</p><h3 id="option-2-—-ssl-certificate-managed-at-the-load-balancer" tabindex="-1">Option 2 — SSL certificate managed at the load balancer <a class="header-anchor" href="#option-2-—-ssl-certificate-managed-at-the-load-balancer" aria-label="Permalink to &quot;Option 2 — SSL certificate managed at the load balancer&quot;">​</a></h3><p>In this option, HTTPS is handled by the customer’s load balancer or network layer. The TeamOne Proxy Server receives trusted internal HTTP traffic from the load balancer.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser / Google Sheets</span></span>
<span class="line"><span>        ↓ HTTPS</span></span>
<span class="line"><span>Load Balancer</span></span>
<span class="line"><span>        ↓ HTTP</span></span>
<span class="line"><span>TeamOne Proxy Server</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>IBM Planning Analytics / TM1</span></span></code></pre></div><p>Use this option when:</p><ul><li>the customer already uses a corporate or cloud load balancer</li><li>certificate management is centralized</li><li>AWS Certificate Manager or another enterprise certificate process is preferred</li></ul><p>In this model, the customer manages the SSL certificate and renewals at the load balancer level. The TeamOne Proxy Server still handles browser preflight requests, rate limiting, request filtering, and forwarding to IBM Planning Analytics / TM1.</p><p>By default, this mode expects the load balancer to forward HTTP traffic to the TeamOne Proxy Server on port <code>80</code>. If the customer’s load balancer uses a different internal target port, the TeamOne Proxy Server configuration can be adjusted accordingly.</p><h3 id="configuration-templates" tabindex="-1">Configuration templates <a class="header-anchor" href="#configuration-templates" aria-label="Permalink to &quot;Configuration templates&quot;">​</a></h3><p>The TeamOne installation package includes example configuration templates for both SSL deployment models:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>config/nginx-https.conf.example</span></span>
<span class="line"><span>config/nginx-http-behind-lb.conf.example</span></span></code></pre></div><p>The selected template is copied to the active configuration file:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>config/default.conf</span></span></code></pre></div><p>Detailed steps for selecting and applying the correct template are provided in the TeamOne Welcome Kit.</p><h2 id="network-and-security-controls" tabindex="-1">Network and security controls <a class="header-anchor" href="#network-and-security-controls" aria-label="Permalink to &quot;Network and security controls&quot;">​</a></h2><p>The TeamOne Proxy Server should be deployed with both network-level and application-level controls.</p><p>The recommended access model is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Inbound:</span></span>
<span class="line"><span>Approved users / corporate network / VPN / Zscaler</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>TeamOne Proxy Server</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Outbound:</span></span>
<span class="line"><span>TeamOne Proxy Server</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Approved IBM Planning Analytics / TM1 hosts and ports only</span></span></code></pre></div><p>Inbound access should be restricted to approved users or approved corporate network paths where possible. Outbound access should be restricted to the IBM Planning Analytics / TM1 hosts and ports that TeamOne is expected to use.</p><p>The TeamOne Proxy Server also includes application-level allowed host controls:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PROXY_ALLOWED_HOST_PATTERN=</span></span>
<span class="line"><span>PROXY_OAUTH_ALLOWED_HOST_PATTERN=</span></span></code></pre></div><p><code>PROXY_ALLOWED_HOST_PATTERN</code> controls which IBM Planning Analytics / TM1 hosts the proxy can forward requests to.</p><p>Example:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PROXY_ALLOWED_HOST_PATTERN=tm1-prod.company.com,tm1-dev.company.com</span></span></code></pre></div><p>Wildcard patterns can also be used for trusted internal domains:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PROXY_ALLOWED_HOST_PATTERN=*.company.internal</span></span></code></pre></div><p><code>PROXY_OAUTH_ALLOWED_HOST_PATTERN</code> controls which OAuth/SSO gateway hosts can be used by the OAuth endpoints.</p><p>Example for IBM Planning Analytics Cloud:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PROXY_OAUTH_ALLOWED_HOST_PATTERN=*.planning-analytics.ibmcloud.com</span></span></code></pre></div><p>Example for IBM Planning Analytics Local with Cognos SSO:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PROXY_OAUTH_ALLOWED_HOST_PATTERN=cognos.company.com</span></span></code></pre></div><p>If SSO/OAuth is not used, this setting can be configured to a non-matching placeholder value to prevent unwanted OAuth redirection:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PROXY_OAUTH_ALLOWED_HOST_PATTERN=disabled.local</span></span></code></pre></div><p>Recommended security practices include:</p><ul><li>restrict inbound access to approved corporate users, networks, VPNs, Zscaler, or source IP ranges where possible</li><li>restrict outbound access to approved IBM Planning Analytics / TM1 hosts and ports</li><li>configure allowed host patterns</li><li>use HTTPS for user-facing access</li><li>keep the TeamOne Proxy Server updated</li></ul><p>The TeamOne Proxy Server does not persist client IBM Planning Analytics / TM1 data. Data is forwarded between TeamOne and IBM Planning Analytics in memory during the request and is not stored by the proxy server.</p>`,71)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
